INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '987a3513-5598-43f2-8f22-af0c75c40101',
  '00000000-0000-0000-0000-000000000001',
  $escape$quic â€” Connection Tracking with NAT and Firewall Rules$escape$,
  $escape$When using quic with iptables or nftables, connection tracking is crucial for proper NAT and firewall functionality. quic's connection IDs are used to identify and track connections, allowing for stateful packet inspection. To enable connection tracking with SNAT (Source NAT) or DNAT (Destination NAT), you must specify the connection ID in the firewall rules. The `ctstate` target is used to track connection states. For example, when using iptables, you can use the `conntrack` target to enable connection tracking: `iptables -t mangle -A OUTPUT -p tcp --ctstate NEW -j CONNMARK --ctdir ORIGINAL_DST`. Similarly, with nftables, you can use the `ct` family to create a connection tracking table.$escape$,
  $escape$iptables -t mangle -A OUTPUT -p tcp --ctstate NEW -j CONNMARK --ctdir ORIGINAL_DST$escape$,
  $escape$bash$escape$,
