INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8c8286cf-dc3e-4cf7-99ec-bd52ca85cdc1',
  '00000000-0000-0000-0000-000000000001',
  $escape$QUIC: When HTTP/3 Beats HTTP/2 in Multiplexing$escape$,
  $escape$When QUIC's connection multiplexing is enabled, HTTP/3 outperforms HTTP/2 due to its reduced head-of-line blocking. QUIC's concurrent stream creation allows multiple streams to transmit data simultaneously, leveraging the available network bandwidth. This is achieved through the quic.ConnectionMultiplexing API, which enables concurrent stream establishment and transmission. As a result, HTTP/3's multiplexing capabilities surpass those of HTTP/2, making it a more reliable choice for high-bandwidth applications.$escape$,
  NULL,
  NULL,
