INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c77d1e57-d97b-4c3f-8b16-a31513de5f90',
  '00000000-0000-0000-0000-000000000001',
  $escape$QuIC TLS Handshake: Session Resumption and 0-RTT Trade-Offs$escape$,
  $escape$When a QuIC client initiates a connection, it performs a TLS handshake using the QUIC_TLS_HANDSHAKE frame. The client and server exchange cryptographic parameters, and the server presents its certificate. The client verifies the server's identity and establishes a secure connection. For subsequent connections, the client can use session resumption to quickly establish a secure connection. However, session resumption requires the server to store the session IDs, which can increase memory usage. 0-RTT (zero round-trip time) handshake allows the client to send encrypted data before the handshake is complete, but it requires the client to have a valid session ticket from a previous connection. The trade-off is that 0-RTT handshake reduces the latency but increases the risk of replay attacks.$escape$,
  NULL,
  NULL,
