INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '369cc39a-81eb-44c2-81c2-43cf1a6a661f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Quic: Tuning Latency vs Throughput with MaxUplinkBandwidth$escape$,
  $escape$When optimizing a Quic connection, balancing latency and throughput is crucial. The `MaxUplinkBandwidth` parameter controls how aggressively the sender transmits data. Set it too high, and you risk increasing latency due to packet reordering and timeouts. Set it too low, and you may not utilize the available bandwidth. The optimal value depends on the underlying network conditions. To experiment with different values, use the `quic_transport_params_set_max_uplink_bandwidth()` function.$escape$,
  $escape$quic_transport_params_set_max_uplink_bandwidth(transport_params, 1000000); // Set uplink bandwidth to 1 Mbps$escape$,
  $escape$c$escape$,
